function LFightRoundData:InitPbRoundData(pb,lifeState)
	self._round = pb.round
	local boutDataList = {}


	for k,v in ipairs(pb.bouts) do
		local boutData = LFightBoutData:New()
		boutData:InitPbBoutData(v,lifeState)
		table.insert(boutDataList,boutData)
	end
	self._totalBout = #boutDataList
	self._boutDataList = boutDataList

	self._speedList = pb.speedList

end

function LFightRoundData:InitJsonRoundData(json)
	self._round = json.round
	local boutDataList = {}
	for k,v in ipairs(json.bouts) do
		local boutData = LFightBoutData:New()
		boutData:InitJsonBoutData(v)
		table.insert(boutDataList,boutData)
	end
	self._totalBout = #boutDataList
	self._boutDataList = boutDataList

	self._speedList = json.speedList
end

function LFightRoundData:GetRound()
	return self._round
end

function LFightRoundData:GetBoutDataList()
	return self._boutDataList
end

function LFightRoundData:GetBoutDataByIndex(index)
	return self._boutDataList[index]
end

function LFightRoundData:GetTotalBout()
	return self._totalBout
end

function LFightRoundData:GetSpeedList()
	return self._speedList
end

function LFightRoundData:GetCurBoutIndex()
	if not self._curBoutIndex then
		self._curBoutIndex = 1
	end
	return self._curBoutIndex
end

---移动游标
function LFightRoundData:ChangeToNextActions()
	local nextActionList,curBoutIndex,curActionIndex = self:GetNextActions()
	self._curBoutIndex = curBoutIndex
	return nextActionList,curBoutIndex,curActionIndex
end

---不移动游标
function LFightRoundData:GetNextActions()
	local curBoutIndex = self._curBoutIndex
	if not curBoutIndex then
		curBoutIndex = 1
	end
	local nextActionList,curActionIndex
	while true do
		local boutData = self._boutDataList[curBoutIndex]
		if not boutData then
			break
		end
		nextActionList,curActionIndex = boutData:GetNextActions()
		if nextActionList then
			break
		end

		curBoutIndex = curBoutIndex + 1
	end

	return nextActionList,curBoutIndex,curActionIndex
end

function LFightBoutData:CreateByPb(pb)
	local boutDataList = {}
	for k,v in ipairs(pb.bouts) do
		local boutData = LFightBoutData:New()
		boutData:InitPbBoutData(v,{})
		table.insert(boutDataList,boutData)
	end
	self._totalBout = #boutDataList
	self._boutDataList = boutDataList

end
